INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (743, 174857, 6, 62, '无题', '平凡枯燥的一天又这么过去了，每天面对这熟悉的面孔，反复看不出什么鲜艳来，可又无奈，既不能抛弃她，又不想背叛她，在这种情绪不知道有多少人反复上演着这段闹剧。脑子浮现出一个这样荒唐的念头，渴望幻想着能找位异性能够与其谈天说笑，人生短短的几十年就这么漫漫度过着，真有些不甘心，就象‘胖子’说的一句话“每天你在都在吃猪肉，自然时间长久就会感觉油腻的”话虽很土，可又很在理。也许外人看我这番话后会想，这人太花，不过又有多少人不是这样的去想和做。。。。。。。。
<br>又要进入一个平凡夜了，时常晚上做着同样的梦，希望永远有着不老的人生，一觉醒来，又变的好累又好烦。日子就这样慢慢的艰熬着，记忆中梦在慢慢的遗忘。。。。。。。。。', '平凡枯燥的一天又这么过去了，每天面对这熟悉的面孔，反复看不出什么鲜艳来，可又无奈，既不能抛弃她，又不想背叛她，在这种情绪不知道有多少人反复上演着这段闹剧。脑子浮现出一个这样荒唐的念头，渴望幻想着能找位异性能够与其谈天说笑，人生短短的几十年就这么漫漫度过着，真有些不甘心，就象‘胖子’说的一句话“每天你在都在吃猪肉，自然时间长久就会感觉油腻的”话虽很土，可又很在理。也许外人看我这番话后会想，这人太花，不过又有多少人不是这样的去想和做。。。。。。。。

又要进入一个平凡夜了，时常晚上做着同样的梦，希望永远有着不老的人生，一觉醒来，又变的好累又好烦。日子就这样慢慢的艰熬着，记忆中梦在慢慢的遗忘。。。。。。。。。', NULL, '2002-08-01 00:24:00', 2, '20020821171811_bbsid_174857_board_6_42e3ff5ba6.html', '20020821171811');
